/* eslint-disable class-methods-use-this */
import * as THREE from 'three';
import { FaceTracker } from '../defaultpipeline.js';
/**
 * Loader for face tracking model data.
 * @see https://docs.zap.works/universal-ar/web-libraries/threejs/face-tracking/
 */
export class FaceTrackerLoader extends THREE.Loader {
    // Implementation that handles both signatures
    load(urlOrCustomModel, onLoadCallback, onProgressCallback, onErrorCallback) {
        // Check if we're using the new required pattern
        // (url is string, onLoad is required, and onProgress has expected signature if provided)
        const isNewPattern = typeof urlOrCustomModel === 'string' && typeof onLoadCallback === 'function' && (!onProgressCallback || onProgressCallback.length !== 0);
        if (isNewPattern) {
            // Handle as new-style (void return)
            const url = urlOrCustomModel;
            const onLoad = onLoadCallback;
            const trk = new FaceTracker();
            const itemFilename = url;
            this.manager.itemStart(itemFilename);
            trk
                .loadModel(url)
                .then(() => {
                onLoad(trk);
                this.manager.itemEnd(itemFilename);
            })
                .catch(err => {
                if (onErrorCallback)
                    onErrorCallback(err);
                this.manager.itemError(itemFilename);
                this.manager.itemEnd(itemFilename);
            });
            return;
        }
        else {
            // Original implementation (returns FaceTracker)
            const customModel = urlOrCustomModel;
            const onLoad = onLoadCallback;
            const onError = onErrorCallback;
            const trk = new FaceTracker();
            const p = customModel ? trk.loadModel(customModel) : trk.loadDefaultModel();
            const itemFilename = typeof customModel === 'string' ? customModel : '__zappar_threejs_face_tracker_default';
            this.manager.itemStart(itemFilename);
            p.then(() => {
                if (onLoad)
                    onLoad(trk);
                this.manager.itemEnd(itemFilename);
            }).catch(_ => {
                if (onError)
                    onError(_);
                this.manager.itemError(itemFilename);
                this.manager.itemEnd(itemFilename);
            });
            return trk;
        }
    }
    /**
     * @ignore
     */
    parse() { }
}
